use aiken/collection/dict
use cardano/transaction.{Transaction, OutputReference}
use cardano/credential.{Credential, ScriptCredential}

pub type WithdrawalDatum {
  required_credential: Credential,
}

pub type WithdrawalRedeemer {
  Check
}

validator withdrawal_check {
  spend(
    datum: Option<WithdrawalDatum>,
    _redeemer: WithdrawalRedeemer,
    _ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let credential = d.required_credential
        dict.has_key(self.withdrawals, credential)
      }
    }
  }

  else(_) {
    fail
  }
}

