use aiken/collection/dict
use cardano/assets
use cardano/transaction.{OutputReference, Transaction}

pub type TokenDatum {
  policy_id: ByteArray,
  min_token_types: Int,
}

validator token_count_gate {
  spend(
    datum: Option<TokenDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(td) -> {
        let outputs = self.outputs
        list.any(
          outputs,
          fn(output) {
            let token_dict = assets.tokens(output.value, td.policy_id)
            dict.size(token_dict) >= td.min_token_types
          },
        )
      }
    }
  }

  else(_) -> Bool {
    False
  }
}

