use aiken/collection/dict
use cardano/transaction.{Transaction, OutputReference}

pub type SumDatum {
  required_total: Int,
}

validator sum_withdrawals {
  spend(datum: Option<SumDatum>, _redeemer: Data, _ref: OutputReference, self: Transaction) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let total =
          dict.foldl(
            self.withdrawals,
            0,
            fn(_cred, amount, acc) { acc + amount },
          )
        total >= d.required_total
      }
    }
  }
}

