use aiken/collection/dict
use cardano/transaction.{Transaction, OutputReference}

pub type ConfigDatum {
  config: dict.Dict<ByteArray, Int>,
  key: ByteArray,
  min_val: Int,
}

validator config_registry(admin: ByteArray) {
  spend(
    datum: Option<ConfigDatum>,
    _redeemer: Data,
    _ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    let admin_signed =
      self.extra_signatories |> list.has(admin)

    when datum is {
      None -> False
      Some(d) ->
        when dict.get(d.config, d.key) is {
          None -> False
          Some(v) -> admin_signed && v >= d.min_val
        }
    }
  }

  else(_) {
    fail
  }
}

use aiken/collection/dict
use cardano/transaction.{Transaction, OutputReference}

pub type RemovalDatum {
  registry: dict.Dict<ByteArray, Int>,
  remove_key: ByteArray,
  owner: ByteArray,
}

validator entry_removal {
  spend(datum: Option<RemovalDatum>, _redeemer: Data, _ref: OutputReference, self: Transaction) -> Bool {
    when datum is {
      None -> False
      Some(d) -> {
        let owner_signed = list.has(self.extra_signatories, d.owner)
        let updated = dict.delete(d.registry, d.remove_key)
        let key_removed = !dict.has_key(updated, d.remove_key)
        owner_signed && key_removed
      }
    }
  }

  else(_) {
    False
  }
}
